"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  PURCHASE_ORDERS,
  STAGES,
  actionFor,
  panelLabelFor,
  purchasingAI,
  type PO,
} from "@/features/ops/api/ops-purchasing-data";
import "./purchasing.css";

const fmtUSD = (v: number) =>
  v >= 1000 ? `$${Math.round(v / 1000)}K` : `$${Math.round(v)}`;

type Filter = "open" | "all" | "intransit" | "drafts" | "history";

const FILTER_KEYS: Filter[] = ["open", "all", "intransit", "drafts", "history"];
const FILTER_LABELS = ["Open", "All", "In transit", "Drafts", "History"];

const FILTER_FN: Record<Filter, (o: PO) => boolean> = {
  open: (o) => o.status < 3,
  all: () => true,
  intransit: (o) => o.status === 1 || o.status === 2,
  drafts: (o) => o.status === 0,
  history: (o) => o.status >= 3,
};

type SortKey = "n" | "supplier" | "linesN" | "landed" | "expSort" | "srcSort" | "status";

const ArrowSvg = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

const SparkIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="1.9">
    <path d="M12 3v4M12 17v4M3 12h4M17 12h4" />
    <circle cx="12" cy="12" r="3" />
  </svg>
);

const Dot = (props: React.HTMLAttributes<HTMLSpanElement>) => <span className="dot" {...props} />;

export default function PurchaseOrdersPage() {
  const [filterIdx, setFilterIdx] = useState(0); // default: Open
  const filter: Filter = FILTER_KEYS[filterIdx];
  const [sortKey, setSortKey] = useState<SortKey>("status");
  const [sortDir, setSortDir] = useState<1 | -1>(1);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [rowActionSent, setRowActionSent] = useState<number | null>(null);
  const [panelBridgeSent, setPanelBridgeSent] = useState(false);
  const [approveAllSent, setApproveAllSent] = useState(false);

  const draftSpotlight = useMemo(
    () => PURCHASE_ORDERS.map((o, i) => ({ o, i })).filter(({ o }) => o.ai),
    [],
  );

  const visible = useMemo(() => {
    const fn = FILTER_FN[filter];
    const arr = PURCHASE_ORDERS.map((o, i) => ({ o, i })).filter(({ o }) => fn(o));
    arr.sort((A, B) => {
      const a = A.o;
      const b = B.o;
      if (sortKey === "n" || sortKey === "supplier") {
        return String(a[sortKey]).localeCompare(String(b[sortKey])) * sortDir;
      }
      if (sortKey === "linesN") {
        return (a.lines.length - b.lines.length) * sortDir;
      }
      const av = (a[sortKey] as unknown as number) ?? 0;
      const bv = (b[sortKey] as unknown as number) ?? 0;
      return (av - bv) * sortDir;
    });
    return arr;
  }, [filter, sortKey, sortDir]);

  const selected = selectedIdx != null ? PURCHASE_ORDERS[selectedIdx] : null;

  const onSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setPanelBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(1);
    }
  };
  const { openBridge } = useBridge();
  /** Per execution map §07 Purchase Orders: action kind → Bridge flow. */
  const actionToPage = (kind: string): BridgePage => {
    if (kind === "chase") return "escalate-po";
    if (kind === "receive") return "receive";
    if (kind === "close") return "update-costs";
    if (kind === "track") return "approve-po";
    // edit / view (drafts)
    return "approve-po";
  };
  const sendRowAction = (i: number, po: PO) => {
    setRowActionSent(i);
    openBridge("ops", actionToPage(actionFor(po).kind));
    setTimeout(() => setRowActionSent(null), 1400);
  };
  const sendPanelBridge = (po: PO) => {
    setPanelBridgeSent(true);
    openBridge("ops", actionToPage(actionFor(po).kind));
    setTimeout(() => setPanelBridgeSent(false), 1800);
  };
  const handleApproveAll = () => {
    setApproveAllSent(true);
    openBridge("ops", "approve-po");
    setTimeout(() => setApproveAllSent(false), 2000);
  };

  const COLS: Array<{ k: SortKey; l: string; num?: boolean }> = [
    { k: "n", l: "PO #" },
    { k: "supplier", l: "Supplier" },
    { k: "linesN", l: "Items", num: true },
    { k: "landed", l: "Total · landed", num: true },
    { k: "expSort", l: "Expected" },
    { k: "srcSort", l: "Source" },
    { k: "status", l: "Status" },
  ];

  return (
    <div className="ops-purchasing-page">
      <DeptHeader
        dept="ops"
        title="Purchase Orders"
        meta={<><span className="live">Live</span> · What you&rsquo;ve ordered, where it is, and what still needs to be sent</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="reorder">+ New PO</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={FILTER_LABELS} activeIndex={filterIdx} onChange={setFilterIdx} />

      {/* ───── KPIs ───── */}
      <div className="po-kpis">
        <div className="po-kpi">
          <div className="lbl">Open POs</div>
          <div className="val">{PURCHASE_ORDERS.filter((o) => o.status < 3).length}</div>
          <div className="sub">
            {PURCHASE_ORDERS.filter((o) => o.status === 0).length} draft ·{" "}
            {PURCHASE_ORDERS.filter((o) => o.status === 1).length} sent ·{" "}
            {PURCHASE_ORDERS.filter((o) => o.status === 2).length} partial
          </div>
        </div>
        <div className="po-kpi">
          <div className="lbl">In transit</div>
          <div className="val">
            {PURCHASE_ORDERS.filter((o) => o.status === 1 || o.status === 2).length}
          </div>
          <div className="sub">next arrival in 2 days</div>
        </div>
        <div className="po-kpi">
          <div className="lbl">Open value · landed</div>
          <div className="val">
            {fmtUSD(
              PURCHASE_ORDERS.filter((o) => o.status < 3).reduce((a, o) => a + o.landed, 0),
            )}
          </div>
          <div className="sub">incl. freight + duties</div>
        </div>
        <div className="po-kpi">
          <div className="lbl">AI-drafted</div>
          <div className="val ai">{draftSpotlight.length}</div>
          <div className="sub">awaiting your approval</div>
        </div>
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={purchasingAI.label} meta={purchasingAI.meta} cards={purchasingAI.cards} />

      {/* ───── Magellan-drafted spotlight ───── */}
      <div className="draft-zone">
        <div className="draft-head">
          <div className="draft-head-l">
            <div className="draft-spark">{SparkIcon}</div>
            <div>
              <div className="draft-ttl">Magellan drafted these from your velocity</div>
              <div className="draft-sub">
                {draftSpotlight.length} SKUs predicted to stock out before a manual reorder could land · nothing sends without your approval
              </div>
            </div>
          </div>
          <button
            className={`draft-approve-all${approveAllSent ? " sent" : ""}`}
            onClick={handleApproveAll}
          >
            {approveAllSent
              ? `All ${draftSpotlight.length} sent to Bridge ✓`
              : `Approve all ${draftSpotlight.length} → Bridge`}
          </button>
        </div>
        <div className="draft-cards">
          {draftSpotlight.map(({ o, i }) => (
            <div key={o.n} className="draft-card" onClick={() => onSelect(i)}>
              <div className="dc-why">
                <Dot />
                {o.why}
              </div>
              <div className="dc-item">
                {o.lines[0].name}
                {o.lines.length > 1 ? ` +${o.lines.length - 1}` : ""}
              </div>
              <div className="dc-sup">{o.supplier} · {o.units} units</div>
              <div className="dc-foot">
                <div className="dc-total">
                  {fmtUSD(o.landed)}<span className="u">landed</span>
                </div>
                <div className="dc-lands">{o.exp}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ───── PO ledger ───── */}
      <div className="po-section-label">All purchase orders</div>
      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          <div className="po-ledger">
            <div className="po-head">
              {COLS.map((c) => {
                const active = sortKey === c.k;
                return (
                  <div
                    key={c.k}
                    className={`th${c.num ? " num" : ""}${active ? " active" : ""}`}
                    onClick={() => handleSort(c.k)}
                  >
                    {c.l}
                    <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                  </div>
                );
              })}
            </div>

            {visible.length === 0 ? (
              <div className="po-empty">No purchase orders in this view</div>
            ) : (
              visible.map(({ o, i }) => {
                const act = actionFor(o);
                return (
                  <div
                    key={o.n}
                    className={`po-row${selectedIdx === i ? " sel" : ""}`}
                    onClick={() => onSelect(i)}
                  >
                    <span className="po-num">{o.n}</span>
                    <span>
                      <span className="po-sup">{o.supplier}</span>
                    </span>
                    <span className="po-items">{o.lines.length}</span>
                    <span className="po-total">
                      {fmtUSD(o.landed)}
                      <span className="u">landed</span>
                    </span>
                    <span className={`po-exp${o.expLate ? " late" : ""}`}>
                      {o.expLate ? `+${o.lateBy} days late` : o.exp}
                      {o.expLate && <span className="micro">was Mar 5</span>}
                    </span>
                    <span>
                      <span className={`po-src${o.ai ? " ai" : ""}`}>
                        <span className="tag">{o.ai ? "AI Reorder" : "Manual"}</span>
                      </span>
                    </span>
                    <span>
                      <span className={`po-pill ${STAGES[o.status].toLowerCase()}`}>
                        {STAGES[o.status]}
                      </span>
                    </span>
                    <button
                      className={`po-act${act.kind === "view" ? " view" : ""}${rowActionSent === i ? " sent" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        sendRowAction(i, o);
                      }}
                    >
                      {rowActionSent === i
                        ? `${act.label} ✓`
                        : (
                          <>
                            {act.label}
                            <ArrowSvg />
                          </>
                        )}
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* ───── Slide-in detail ───── */}
        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="pd-empty">
                <div className="ttl">Inspect a purchase order</div>
                <div className="lead">
                  Click any PO to see its line items, landed total, where it is in the pipeline, and the cash it commits — then approve or submit via Bridge.
                </div>
              </div>
            ) : (
              <>
                <div className="pd-head">
                  <div>
                    <div className="pd-num">
                      {selected.n}
                      {selected.ai ? " · AI Reorder" : ""}
                    </div>
                    <div className="pd-sup">{selected.supplier}</div>
                    <div className="pd-meta">
                      {selected.units} units · {selected.lines.length} line
                      {selected.lines.length > 1 ? "s" : ""}
                    </div>
                  </div>
                  <button className="pd-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>

                {/* Stage pipeline */}
                <div className="pd-stages">
                  {STAGES.map((s, i) => {
                    const cls = i < selected.status ? "done" : i === selected.status ? "cur" : "";
                    return (
                      <div key={s} className={`pd-stage ${cls}`}>
                        <span className="node" />
                        <span className="nm">{s}</span>
                      </div>
                    );
                  })}
                </div>

                {/* Lines */}
                <div className="pd-lines">
                  {selected.lines.map((l) => (
                    <div key={l.name} className="pd-line">
                      <div>
                        <div className="li-n">{l.name}</div>
                        <div className="li-q">
                          {l.qty} units × {fmtUSD(l.landedUnit)} landed
                        </div>
                      </div>
                      <div className="li-v">{fmtUSD(l.qty * l.landedUnit)}</div>
                    </div>
                  ))}
                </div>

                {/* Totals */}
                <div className="pd-totals">
                  <div className="pd-trow">
                    <span className="l">Items</span>
                    <span className="v">{fmtUSD(selected.itemsTotal)}</span>
                  </div>
                  <div className="pd-trow">
                    <span className="l">Freight</span>
                    <span className="v">{fmtUSD(selected.freight)}</span>
                  </div>
                  <div className="pd-trow">
                    <span className="l">Duties</span>
                    <span className="v">{fmtUSD(selected.duty)}</span>
                  </div>
                  <div className="pd-trow grand">
                    <span className="l">Landed total</span>
                    <span className="v">{fmtUSD(selected.landed)}</span>
                  </div>
                </div>

                {/* Runway */}
                <div className="pd-runway">
                  <div className="rh">Runway &amp; cash impact</div>
                  <div className="rb">
                    {selected.runway}{" "}
                    <a href="/ops/capital-horizon">See in Capital Horizon →</a>
                  </div>
                </div>

                {/* Bridge buttons */}
                <button
                  className={`pd-bridge${panelBridgeSent ? " sent" : ""}`}
                  onClick={() => sendPanelBridge(selected)}
                >
                  {panelBridgeSent
                    ? panelLabelFor(selected).replace("→ Bridge", "sent ✓")
                    : panelLabelFor(selected)}
                </button>
                {selected.status === 0 && (
                  <button className="pd-bridge secondary" onClick={() => setSelectedIdx(null)}>
                    Adjust draft
                  </button>
                )}
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
