/**
 * Mock data for the Operations · Purchase Orders sub-page.
 *
 * Each PO is staged on a 5-step pipeline: Draft → Sent → Partial → Received → Closed.
 * AI-drafted POs (kind === "ai") light up the spotlight zone at the top.
 * Late shipments are flagged via `lateBy` (days past the original ETA).
 */

export type POStage = 0 | 1 | 2 | 3 | 4;
export type POLine = { name: string; qty: number; landedUnit: number };

export interface PORaw {
  n: string;
  supplier: string;
  status: POStage;
  ai: boolean;
  /** Why Magellan drafted (or any flag): shown on draft cards */
  why?: string;
  /** Expected text — either a date or a phrase ("submit today", "partial · 60/150", etc.) */
  exp: string;
  expLate?: boolean;
  lateBy?: number;
  lines: POLine[];
  freight: number;
  duty: number;
  runway: string;
}

export interface PO extends PORaw {
  itemsTotal: number;
  landed: number;
  units: number;
  /** Sort proxy: late goes first, then open by index, then history last */
  expSort: number;
  /** AI sorts before manual */
  srcSort: 0 | 1;
}

