export const PURCHASE_ORDERS: PO[] = RAW.map((o, i) => {
  const itemsTotal = o.lines.reduce((a, l) => a + l.qty * l.landedUnit, 0);
  const landed = itemsTotal + o.freight + o.duty;
  const units = o.lines.reduce((a, l) => a + l.qty, 0);
  const expSort = o.expLate ? -100 + (o.lateBy ?? 0) : o.status >= 3 ? 9000 + i : 100 + i;
  const srcSort: 0 | 1 = o.ai ? 0 : 1;
  return { ...o, itemsTotal, landed, units, expSort, srcSort };
});

export const STAGES = ["Draft", "Sent", "Partial", "Received", "Closed"] as const;

export type ActionKind = "edit" | "chase" | "track" | "receive" | "close" | "view";

export const ACTION_LABEL_LEDGER: Record<ActionKind, string> = {
  edit: "Edit",
  chase: "Chase",
  track: "Track",
  receive: "Receive",
  close: "Close",
  view: "View",
};

export const ACTION_LABEL_PANEL: Record<ActionKind, string> = {
  edit: "Approve & submit → Bridge",
  chase: "Chase supplier → Bridge",
  track: "Track shipment → Bridge",
  receive: "Receive remaining → Bridge",
  close: "Close & reconcile → Bridge",
  view: "View in Bridge",
};

export function actionFor(o: PO): { label: string; kind: ActionKind } {
  if (o.status === 0) return { label: ACTION_LABEL_LEDGER.edit, kind: "edit" };
  if (o.status === 1)
    return o.expLate
      ? { label: ACTION_LABEL_LEDGER.chase, kind: "chase" }
      : { label: ACTION_LABEL_LEDGER.track, kind: "track" };
  if (o.status === 2) return { label: ACTION_LABEL_LEDGER.receive, kind: "receive" };
  if (o.status === 3) return { label: ACTION_LABEL_LEDGER.close, kind: "close" };
  return { label: ACTION_LABEL_LEDGER.view, kind: "view" };
}

export function panelLabelFor(o: PO): string {
  const { kind } = actionFor(o);
  if (kind === "edit") return o.ai ? "Approve & submit → Bridge" : "Edit & submit → Bridge";
  return ACTION_LABEL_PANEL[kind];
}

